import React from "react";
import { Route, Redirect } from "react-router-dom";

const AdminSuperProtectedRoute = ({ component: Component, ...rest }) => {
  const raw = localStorage.getItem("adminJwt");
  let isAuthed = false;
  try {
    isAuthed = !!raw && JSON.parse(raw).token;
  } catch (e) {
    isAuthed = false;
  }
  return (
    <Route
      {...rest}
      render={(props) =>
        isAuthed ? <Component {...props} /> : <Redirect to={{ pathname: "/admin/login" }} />
      }
    />
  );
};

export default AdminSuperProtectedRoute;
